# alerting/notifiers.py
import smtplib
import json
import urllib.request
from email.message import EmailMessage
from dataclasses import dataclass
from enum import Enum


class Severity(str, Enum):
    INFO = "info"
    WARNING = "warning"
    CRITICAL = "critical"


@dataclass
class Alert:
    title: str
    message: str
    severity: Severity
    pipeline: str
    run_id: str


class SlackNotifier:
    def __init__(self, webhook_url: str):
        self.webhook_url = webhook_url

    def send(self, alert: Alert) -> None:
        color_map = {
            Severity.INFO: "#36a64f",
            Severity.WARNING: "#FFA500",
            Severity.CRITICAL: "#FF0000",
        }
        payload = {
            "attachments": [{
                "color": color_map[alert.severity],
                "title": f"[{alert.severity.upper()}] {alert.title}",
                "text": alert.message,
                "fields": [
                    {"title": "Pipeline", "value": alert.pipeline, "short": True},
                    {"title": "Run ID", "value": alert.run_id, "short": True},
                ],
                "footer": "Data Pipeline Monitor",
            }]
        }
        data = json.dumps(payload).encode("utf-8")
        req = urllib.request.Request(
            self.webhook_url,
            data=data,
            headers={"Content-Type": "application/json"},
        )
        urllib.request.urlopen(req, timeout=10)


class PagerDutyNotifier:
    EVENTS_URL = "https://events.pagerduty.com/v2/enqueue"

    def __init__(self, integration_key: str):
        self.integration_key = integration_key

    def send(self, alert: Alert) -> None:
        severity_map = {
            Severity.INFO: "info",
            Severity.WARNING: "warning",
            Severity.CRITICAL: "critical",
        }
        payload = {
            "routing_key": self.integration_key,
            "event_action": "trigger",
            "dedup_key": f"{alert.pipeline}:{alert.title}",  # prevents duplicate pages
            "payload": {
                "summary": alert.title,
                "severity": severity_map[alert.severity],
                "source": alert.pipeline,
                "custom_details": {
                    "run_id": alert.run_id,
                    "message": alert.message,
                },
            },
        }
        data = json.dumps(payload).encode("utf-8")
        req = urllib.request.Request(
            self.EVENTS_URL,
            data=data,
            headers={"Content-Type": "application/json"},
        )
        urllib.request.urlopen(req, timeout=10)


class CompositeNotifier:
    """Fan-out to multiple notification channels."""
    def __init__(self, notifiers):
        self.notifiers = notifiers

    def send(self, alert: Alert) -> None:
        errors = []
        for notifier in self.notifiers:
            try:
                notifier.send(alert)
            except Exception as e:
                errors.append(str(e))
        if errors:
            # Don't suppress the original alert failure silently
            print(f"WARNING: Some notifications failed: {errors}")
